    Pattern pattern = Pattern.compile("(\\w+)");
    Matcher matcher = pattern.matcher(defaultString);

    try {
        return matcher.matches() ? matcher.group(1) : defaultString;
    } catch (PatternSyntaxException e) {
        // Handle the case where the regex is invalid
        System.err.println("Invalid regular expression: " + pattern.toString());
        return defaultString;
    }
}

