public String getGroupNameOrDefault(String input, int group) {
    // Define a matcher pattern for the specific group
    Pattern pattern = Pattern.compile("(?<group>" + group + "\\w+)");

    // Create a matcher object to search within the input string
    Matcher matcher = pattern.matcher(input);

    // Check if a match is found
    if (matcher.find()) {
        // Return the matched group if it exists, otherwise return defaultString
        return matcher.group("group");
    } else {
        // Return defaultString if no match is found
        return "";
    }
}

