public static RunListener wrapRunListener(RunListener listener) {
    // Check if the listener is annotated with @RunListener.ThreadSafe
    if (listener.getClass().isAnnotationPresent(RunListener.ThreadSafe.class)) {
        return listener;
    } else {
        // Create a new SynchronizedRunListener instance wrapping the provided listener and this context
        return new SynchronizedRunListener(listener, RunListener.this);
    }
}

