{
    Map<Class<? extends Annotation>, List<FrameworkMethod>> methodsForAnnotations = new LinkedHashMap<>();

    // This loop goes through each method in the test class and checks for annotations on that method.
    for (FrameworkMethod method : getDeclaredMethods()) {
        // Check if the method has any annotations of type Class<? extends Annotation>
        for (Annotation annotation : method.getAnnotations()) {
            // Get the annotation type
            Class<? extends Annotation> annotationType = annotation.getClass();

            // If this is the first time we see an instance of this annotation type, create a new list to store methods with that annotation.
            if (!methodsForAnnotations.containsKey(annotationType)) {
                methodsForAnnotations.put(annotationType, new ArrayList<>());
            }

            // Add the current method to the list for its annotation type.
            methodsForAnnotations.get(annotationType).add(method);
        }
    }
}

