    Map<Class<? extends Annotation>, List<FrameworkMethod>> methodsForAnnotations = new LinkedHashMap<Class<? extends Annotation>, List<FrameworkMethod>>();

    // Loop through each annotation type to retrieve corresponding FrameworkMethods
    for (Class<? extends Annotation> annotationType : annotationTypes) {
        List<FrameworkMethod> frameworkMethods = new ArrayList<>();

        // Get all methods annotated with the current annotation type
        Method[] methods = annotationType.getDeclaredMethods();

        // Iterate over each method and add it to the list if it is a FrameworkMethod
        for (Method method : methods) {
            if (method.isAnnotationPresent(FrameworkMethod.class)) {
                frameworkMethods.add((FrameworkMethod) method);
            }
        }

        // Add the list of framework methods to the map with the annotation type as the key
        methodsForAnnotations.put(annotationType, frameworkMethods);
    }
}

