    Map<Class<? extends Annotation>, List<FrameworkMethod>> methodsForAnnotations = new LinkedHashMap<>();

    // Get all methods in the current class and its superclasses
    Method[] methods = getClass().getMethods();

    // Iterate through each method
    for (Method method : methods) {
        // Check if the method is annotated with a specific annotation
        if (method.isAnnotationPresent(SomeAnnotation.class)) {
            // Get the annotation from the method
            SomeAnnotation annotation = method.getAnnotation(SomeAnnotation.class);

            // Create a new list to store methods with the same annotation
            List<FrameworkMethod> methodsForAnnotation = new ArrayList<>();

            // Add the current method to the list of methods for this annotation
            methodsForAnnotation.add(new FrameworkMethod(method));

            // Put the annotation type and the list of methods in the map
            methodsForAnnotations.put(annotation.getClass(), methodsForAnnotation);
        }
    }
}

