{
    Map<Class<? extends Annotation>, List<FrameworkMethod>> methodsForAnnotations = new LinkedHashMap<>();

    // Iterate through all classes in the current thread's context class loader
    for (Class<?> clazz : Thread.currentThread().getContextClassLoader().getClasses()) {
        // Get all annotations on the class and its methods
        Annotation[] annotations = clazz.getAnnotations();

        for (Annotation annotation : annotations) {
            // Check if the annotation is an instance of the desired type
            if (annotation instanceof MyCustomAnnotation) {
                List<FrameworkMethod> methods = new ArrayList<>();

                // Iterate through all methods in the class
                for (Method method : clazz.getDeclaredMethods()) {
                    // Check if the method has the desired annotation
                    if (method.isAnnotationPresent(MyCustomAnnotation.class)) {
                        methods.add(new FrameworkMethod(method));
                    }
                }

                // Add the annotated methods to the map
                methodsForAnnotations.put((Class<? extends Annotation>) annotation, methods);
            }
        }
    }
}

