public void collectMethodsForAnnotations() {
    Map<Class<? extends Annotation>, List<FrameworkMethod>> methodsForAnnotations = new LinkedHashMap<>();

    // Iterate over all methods in the test classes and add them to the map based on their annotations.
    for (Class<?> testClass : getTestClassHierarchy()) {
        for (FrameworkMethod method : testClass.getDeclaredMethods()) {
            for (Annotation annotation : method.getAnnotations()) {
                Class<? extends Annotation> annotationType = annotation.annotationType();
                methodsForAnnotations.computeIfAbsent(annotationType, k -> new ArrayList<>()).add(method);
            }
        }
    }
}

